    `${messages.doneLabel}: ${stats.done}`,
    `${messages.openLabel}: ${stats.open}`,
    `${messages.hoursLabel}: ${stats.hours}h`,
  ];
}

function renderFooter(
  stats: { done: number; hours: number },
  totalTasks: number,
  messages: typeof MESSAGES[keyof typeof MESSAGES]
): string[] {
  return [`${stats.done}/${totalTasks} ${messages.done}, ${stats.hours}h ${messages.total}`];
}

export function formatReport(input: ReportInput, options?: ReportOptions): string {
  const opts = { ...DEFAULT_OPTIONS, ...options };

  const theme = THEMES[opts.theme as keyof typeof THEMES];
  if (!theme) {
    throw new Error(`no theme registered under: ${opts.theme}`);
  }

  const messages = MESSAGES[opts.locale as keyof typeof MESSAGES];
  if (!messages) {
    throw new Error(`no messages for locale: ${opts.locale}`);
  }

  const lines: string[] = [];
  const stats = getTaskStats(input.tasks);

  for (const section of opts.sections) {
    if (section === "header") {
      lines.push(...renderHeader(input.title, opts.separator));
    } else if (section === "tasks") {
      lines.push(...renderTasks(input.tasks, opts.bullet, theme));
    } else if (section === "summary") {
      lines.push(...renderSummary(stats, messages));
    } else if (section === "footer") {
      lines.push(...renderFooter(stats, input.tasks.length, messages));
    } else {
      throw new Error(`no renderer for section: ${section}`);
    }
  }

  return lines.join("\n");
}

