/**
 * Task report module.
 *
 * Formats a list of tasks into a plain-text report: a title header, one line
 * per task, an optional summary section, and a footer with totals. The public
 * surface is `formatReport` and the option/type exports; everything else is
 * internal machinery.
 */

export interface Task {
  title: string;
  done: boolean;
  hours: number;
}

export interface ReportInput {
  title: string;
  tasks: Task[];
}

export interface ReportOptions {
  separator?: string;
  bullet?: string;
  sections?: string[];
  theme?: string;
  locale?: string;
  outputFormat?: "text";
}

// Available themes with their character sets
const THEMES = {
  default: {
    separator: "=",
    bullet: "-",
    doneMarker: "[x]",
    openMarker: "[ ]",
  },
};

// Localized message strings
const MESSAGES = {
  en: {
    done: "done",
    total: "total",
    doneLabel: "Done",
    openLabel: "Open",
    hoursLabel: "Hours",
  },
};

// Report generation defaults
const DEFAULT_OPTIONS = {
  separator: "=",
  bullet: "-",
  sections: ["header", "tasks", "footer"],
  theme: "default",
  locale: "en",
  outputFormat: "text",
};

function renderHeader(input: ReportInput, separator: string): string[] {
  const title = input.title;
  const underline = separator.repeat(title.length);
  return [title, underline];
}

function renderTasks(input: ReportInput, bullet: string, doneMarker: string, openMarker: string): string[] {
  const taskLines: string[] = [];
  for (const task of input.tasks) {
    const marker = task.done ? doneMarker : openMarker;
    const line = `${bullet} ${marker} ${task.title} (${task.hours}h)`;
    taskLines.push(line);
  }
  return taskLines;
}

function renderSummary(input: ReportInput, messages: Record<string, string>): string[] {
  let doneCount = 0;
  let openCount = 0;
  let totalHours = 0;

  for (const task of input.tasks) {
    if (task.done) {
      doneCount++;
    } else {
      openCount++;
    }
    totalHours += task.hours;
  }

  return [
    `${messages.doneLabel}: ${doneCount}`,
    `${messages.openLabel}: ${openCount}`,
    `${messages.hoursLabel}: ${totalHours}h`,
  ];
}

function renderFooter(input: ReportInput, messages: Record<string, string>): string[] {
  let doneCount = 0;
  let totalHours = 0;

  for (const task of input.tasks) {
    if (task.done) {
      doneCount++;
    }
    totalHours += task.hours;
  }

  const total = input.tasks.length;
  const line = `${doneCount}/${total} ${messages.done}, ${totalHours}h ${messages.total}`;
  return [line];
}

export function formatReport(input: ReportInput, options?: ReportOptions): string {
  // Merge provided options with defaults
  const opts = { ...DEFAULT_OPTIONS, ...(options ?? {}) };

  // Validate and resolve theme
  const theme = THEMES[opts.theme as keyof typeof THEMES];
  if (!theme) {
    throw new Error(`no theme registered under: ${opts.theme}`);
  }

  // Validate and resolve messages
  const messages = MESSAGES[opts.locale as keyof typeof MESSAGES];
  if (!messages) {
    throw new Error(`no messages for locale: ${opts.locale}`);
  }

  // Render each requested section
  const lines: string[] = [];
  for (const section of opts.sections) {
    if (section === "header") {
      lines.push(...renderHeader(input, opts.separator));
    } else if (section === "tasks") {
      lines.push(...renderTasks(input, opts.bullet, theme.doneMarker, theme.openMarker));
    } else if (section === "summary") {
      lines.push(...renderSummary(input, messages));
    } else if (section === "footer") {
      lines.push(...renderFooter(input, messages));
    } else {
      throw new Error(`no renderer for section: ${section}`);
    }
  }

  // Return all lines as a single string
  return lines.join("\n");
}

